package com.google.gson.stream;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.io.Writer;
import java.lang.reflect.Field;

public class JsonWriterTest {
  private Writer mockWriter;
  private JsonWriter jsonWriter;

  @BeforeEach
  public void setUp() throws Exception {
    mockWriter = mock(Writer.class);
    jsonWriter = new JsonWriter(mockWriter);

    // Use reflection to set stackSize to 1 (non-zero) to simulate open writer
    Field stackSizeField = JsonWriter.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(jsonWriter, 1);
  }

  @Test
  public void flush_writerOpen_callsFlushOnOut() throws IOException {
    jsonWriter.flush();
    verify(mockWriter, times(1)).flush();
  }

  @Test
  public void flush_writerClosed_throwsIllegalStateException() throws Exception {
    // Set stackSize to 0 to simulate closed writer
    Field stackSizeField = JsonWriter.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(jsonWriter, 0);

    IllegalStateException exception = assertThrows(IllegalStateException.class, () -> jsonWriter.flush());
    assertEquals("JsonWriter is closed.", exception.getMessage());

    verify(mockWriter, never()).flush();
  }

  @Test
  public void flush_writerOpen_flushThrowsIOException_propagates() throws IOException {
    doThrow(new IOException("flush failed")).when(mockWriter).flush();

    IOException exception = assertThrows(IOException.class, () -> jsonWriter.flush());
    assertEquals("flush failed", exception.getMessage());
  }
}
